from __future__ import annotations

import asyncio
from collections.abc import Awaitable, Callable, Iterable


async def _drain_running(tasks: Iterable[asyncio.Task[None]]) -> None:
    running = [task for task in tasks if not task.done()]
    if not running:
        return

    current = asyncio.current_task()
    cleared_cancellations = 0

    # Allow started tasks to finish their cancellation cleanup before
    # propagating cancellation back to the caller.
    if current is not None and hasattr(current, "uncancel"):
        while current.cancelling():
            current.uncancel()
            cleared_cancellations += 1

    try:
        await asyncio.gather(*running, return_exceptions=True)
    finally:
        if current is not None:
            for _ in range(cleared_cancellations):
                current.cancel()


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int
) -> None:
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    pending = iter(tasks)
    running: set[asyncio.Task[None]] = set()

    def start_ready_tasks() -> bool:
        started_any = False
        while len(running) < max_concurrent:
            try:
                task_factory = next(pending)
            except StopIteration:
                break

            running.add(asyncio.create_task(task_factory()))
            started_any = True

        return started_any

    try:
        start_ready_tasks()

        while running:
            done, _ = await asyncio.wait(
                running, return_when=asyncio.FIRST_COMPLETED
            )

            running.difference_update(done)

            first_error: BaseException | None = None
            for task in done:
                try:
                    task.result()
                except asyncio.CancelledError:
                    continue
                except BaseException as exc:
                    if first_error is None:
                        first_error = exc

            if first_error is not None:
                raise first_error

            start_ready_tasks()
    except BaseException:
        for task in running:
            task.cancel()
        await _drain_running(running)
        raise
